### Swift Variadic Parameters

Variadic parameters accept zero or more values of a specified type. They are indicated by three dots `...` after the type and are accessed as an array inside the function.

**Variadic Syntax:**

```swift
func functionName(_ values: Type...) {
    // values is [Type]
}

func sum(_ numbers: Int...) -> Int {
    return numbers.reduce(0, +)
}

print(sum(1, 2, 3))      // 6
print(sum(10, 20))       // 30
print(sum())             // 0 (empty)
```

**Key Rules:**

| Rule | Description |
|------|-------------|
| Only one variadic | A function can have at most one variadic parameter |
| Position | Must be the last parameter (unless followed by a parameter with a default value) |
| Empty allowed | Calling with no arguments creates an empty array |
| Type safety | All arguments must match the declared type |

```swift
// Variadic with regular parameters
func greet(message: String, names: String...) {
    for name in names {
        print("\(message), \(name)!")
    }
}

greet(message: "Hello", names: "Alice", "Bob", "Charlie")
// Hello, Alice!
// Hello, Bob!
// Hello, Charlie!

// Variadic with default parameter
func log(_ level: String = "INFO", messages: String...) {
    for msg in messages {
        print("[\(level)] \(msg)")
    }
}

log(messages: "System starting", "Loading config")
log(level: "ERROR", messages: "File not found", "Permission denied")
```

> **Key Point:** Inside the function, a variadic parameter is an array. You can iterate over it, use array methods, or pass it to other functions.

```swift
func average(_ numbers: Double...) -> Double {
    guard !numbers.isEmpty else { return 0 }
    return numbers.reduce(0, +) / Double(numbers.count)
}

print(average(1.0, 2.5, 3.0, 4.5))  // 2.75
```

codeExample:
import Foundation

// Variadic sum
func total(_ values: Double...) -> Double {
    values.reduce(0, +)
}

print("Total: \(total(10.5, 20.3, 30.7))")
print("Empty total: \(total())")

// Variadic with other parameters
func buildSentence(_ words: String..., withPunctuation punctuation: String = ".") -> String {
    words.joined(separator: " ") + punctuation
}

print(buildSentence("Swift", "is", "awesome", withPunctuation: "!"))
print(buildSentence("Hello", "World"))

// Variadic with mixed types using generics (simplified)
func concatenate(_ separator: String, _ strings: String...) -> String {
    strings.joined(separator: separator)
}

let csv = concatenate(", ", "Alice", "Bob", "Charlie")
print("CSV: \(csv)")
